import React, { useEffect, useState, useCallback } from 'react';
import api from '../api/axiosConfig';
import { useTheme } from '../context/ThemeContext';
import ReactMarkdown from 'react-markdown';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X, BarChart3, AlignLeft } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { isDark } = useTheme(); // This must be working for the fix to apply
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  const fetchHistory = useCallback(async () => {
    try {
      const res = await api.get('/portfolio/history');
      setHistory(res.data);
    } catch (err) {
      toast.error("VAULT_SYNC_FAILURE");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchHistory(); }, [fetchHistory]);

  const handleDownload = async (item) => {
    try {
      const response = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Strategy_${item.id}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (err) { toast.error("EXPORT_FAILED"); }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("PERMANENT_PURGE: Proceed?")) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success("DELETED");
    } catch (err) { toast.error("PURGE_ERROR"); }
  };

  if (loading) return <div style={centerStyle}>SYNCHRONIZING_VAULT...</div>;

  return (
    <div style={containerStyle(isDark)}>
      <div style={headerRow(isDark)}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
          <Archive size={24} color="var(--accent-primary)"/>
          <h2 style={{ color: isDark ? '#fff' : '#000', margin: 0, fontSize: '1.4rem' }}>STRATEGY_VAULT</h2>
        </div>
        <span style={vaultBadge}>{history.length} NODES</span>
      </div>

      <div style={listStyle}>
        {history.map((item) => (
          <div key={item.id} style={cardStyle(isDark)}>
            <div style={{ flex: 1 }}>
              <div style={tagRow}>
                <span style={{ fontSize: '0.75rem', color: isDark ? '#888' : '#666', display: 'flex', alignItems: 'center', gap: '5px' }}>
                  <Calendar size={12}/> {new Date(item.created_at).toLocaleDateString()}
                </span>
                <span style={{ fontSize: '0.75rem', color: 'var(--accent-primary)', fontWeight: 800 }}>
                  <ShieldCheck size={12}/> RISK: {item.risk_score}
                </span>
              </div>
              <h4 style={{ color: isDark ? '#fff' : '#000', margin: '0 0 10px 0', fontSize: '1.1rem' }}>{item.goal}</h4>
            </div>

            <div style={actionColumn(isDark)}>
              <button onClick={() => setSelectedItem(item)} style={iconBtn(isDark)}><Eye size={18}/></button>
              <button onClick={() => handleDownload(item)} style={iconBtn(isDark)}><Download size={18}/></button>
              <button onClick={() => handleDelete(item.id)} style={{ ...iconBtn(isDark), color: '#ef4444' }}><Trash2 size={18}/></button>
            </div>
          </div>
        ))}
      </div>

      {/* ── THEME FIXED MODAL (FORCED BLACK) ── */}
      {selectedItem && (
        <div style={modalOverlay(isDark)}>
          <div style={modalContent(isDark)}>
            <div style={modalHeader(isDark)}>
              <span style={{ color: 'var(--accent-primary)', fontFamily: 'monospace', fontWeight: 800 }}>
                NODE_DATA // ID_{selectedItem.id}
              </span>
              <button onClick={() => setSelectedItem(null)} style={closeBtn(isDark)}><X size={24}/></button>
            </div>
            
            <div style={modalBody(isDark)}>
              <h3 style={{ color: isDark ? '#fff' : '#000', fontSize: '1.5rem', marginBottom: '1.5rem' }}>
                {selectedItem.goal}
              </h3>
              
              <p style={labelSmall}><AlignLeft size={14}/> STRATEGIC_SUMMARY</p>
              <div style={{ color: isDark ? '#ccc' : '#333', lineHeight: '1.6', marginBottom: '2rem' }}>
                <ReactMarkdown>{selectedItem.summary}</ReactMarkdown>
              </div>

              <p style={labelSmall}><AlignLeft size={14}/> AGENTIC_RATIONALE</p>
              <div style={{ color: isDark ? '#ccc' : '#333', lineHeight: '1.6' }}>
                <ReactMarkdown>{selectedItem.rationale}</ReactMarkdown>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

/* ─────────────────────────────── Styles ─────────────────────────────── */

const containerStyle = (isDark) => ({ 
  padding: '3rem 1.5rem', 
  maxWidth: '900px', 
  margin: '0 auto',
  minHeight: '100vh',
  background: isDark ? '#000000' : '#ffffff' 
});

const headerRow = (isDark) => ({ 
  display: 'flex', 
  justifyContent: 'space-between', 
  alignItems: 'center', 
  marginBottom: '2rem', 
  borderBottom: `1px solid ${isDark ? '#222' : '#eee'}`, 
  paddingBottom: '1rem' 
});

const vaultBadge = { fontSize: '0.7rem', color: 'var(--accent-primary)', fontWeight: 800, padding: '4px 10px', borderRadius: '5px', border: '1px solid var(--accent-primary)' };
const listStyle = { display: 'flex', flexDirection: 'column', gap: '1rem' };

const cardStyle = (isDark) => ({ 
  display: 'flex', 
  padding: '1.5rem', 
  border: `1px solid ${isDark ? '#222' : '#eee'}`, 
  borderRadius: '12px', 
  background: isDark ? '#0a0a0a' : '#f9f9f9',
  alignItems: 'center'
});

const tagRow = { display: 'flex', gap: '15px', marginBottom: '8px' };
const actionColumn = (isDark) => ({ display: 'flex', gap: '15px', borderLeft: `1px solid ${isDark ? '#222' : '#eee'}`, paddingLeft: '1.5rem', marginLeft: '1rem' });
const iconBtn = (isDark) => ({ background: 'none', border: 'none', color: isDark ? '#888' : '#444', cursor: 'pointer' });

const modalOverlay = (isDark) => ({
  position: 'fixed', inset: 0,
  background: isDark ? 'rgba(0, 0, 0, 0.95)' : 'rgba(255, 255, 255, 0.9)',
  backdropFilter: 'blur(10px)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 9999
});

const modalContent = (isDark) => ({
  width: '90%', maxWidth: '750px',
  background: isDark ? '#000000' : '#ffffff', // FORCED
  border: `1px solid ${isDark ? '#333' : '#ddd'}`,
  borderRadius: '15px', maxHeight: '80vh', display: 'flex', flexDirection: 'column', overflow: 'hidden'
});

const modalHeader = (isDark) => ({
  padding: '1rem 1.5rem', borderBottom: `1px solid ${isDark ? '#222' : '#eee'}`,
  display: 'flex', justifyContent: 'space-between', alignItems: 'center',
  background: isDark ? '#080808' : '#f5f5f5'
});

const modalBody = (isDark) => ({ 
  padding: '2rem', overflowY: 'auto', 
  background: isDark ? '#000000' : '#ffffff' 
});

const labelSmall = { fontSize: '0.7rem', fontWeight: 900, color: 'var(--accent-primary)', marginBottom: '0.5rem', display: 'flex', alignItems: 'center', gap: '5px' };
const closeBtn = (isDark) => ({ background: 'none', border: 'none', color: isDark ? '#fff' : '#000', cursor: 'pointer' });
const centerStyle = { height: '80vh', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--accent-primary)', fontFamily: 'monospace' };

export default VaultPage;
